{"content":"#!/usr/bin/env python3
"""Merge user data from three sources with conflict resolution."""

import json
import pandas as pd
from datetime import datetime

# Field mappings
FIELD_MAP = {
    'id': 'user_id',
    'userId': 'user_id',
    'user_id': 'user_id',
    'full_name': 'name',
    'name': 'name',
    'userName': 'name',
    'email': 'email',
    'email_address': 'email',
    'registration_date': 'created_date',
    'created_at': 'created_date',
    'joined': 'created_date',
}

# Status field mapping
STATUS_MAP = {
    'status': 'status',
    'is_active': 'status',
    'active': 'status',
}


def normalize_status(value):
    """Normalize status values to consistent string."""
    if isinstance(value, bool):
        return 'active' if value else 'inactive'
    if isinstance(value, str):
        val = value.lower()
        if val in ('true', 'active', 'yes'):
            return 'active'
        elif val in ('false', 'inactive', 'no'):
            return 'inactive'
    return str(value)


def normalize_date(date_str):
    """Ensure date is in YYYY-MM-DD format."""
    try:
        dt = datetime.strptime(date_str, '%Y-%m-%d')
        return dt.strftime('%Y-%m-%d')
    except ValueError:
        try:
            dt = datetime.strptime(date_str, '%Y/%m/%d')
            return dt.strftime('%Y-%m-%d')
        except ValueError:
            return date_str


def load_source_a():
    """Load source A (JSON)."""
    with open('/data/source_a/users.json', 'r') as f:
        data = json.load(f)
    records = []
    for row in data:
        rec = {}
        for k, v in row.items():
            if k in FIELD_MAP:
                rec[FIELD_MAP[k]] = v
            elif k in STATUS_MAP:
                rec['status'] = normalize_status(v)
        records.append(rec)
    return records


def load_source_b():
    """Load source B (CSV)."""
    df = pd.read_csv('/data/source_b/users.csv')
    records = []
    for _, row in df.iterrows():
        rec = {}
        for k, v in row.items():
            if k in FIELD_MAP:
                rec[FIELD_MAP[k]] = v
            elif k in STATUS_MAP:
                rec['status'] = normalize_status(v)
        records.append(rec)
    return records


def load_source_c():
    """Load source C (Parquet)."""
    df = pd.read_parquet('/data/source_c/users.parquet')
    records = []
    for _, row in df.iterrows():
        rec = {}
        for k, v in row.items():
            if k in FIELD_MAP:
                rec[FIELD_MAP[k]] = v
            elif k in STATUS_MAP:
                rec['status'] = normalize_status(v)
        records.append(rec)
    return records


def detect_conflicts(users_by_source):
    """Detect conflicts across sources for each user."""
    conflicts = []
    all_user_ids = set()
    for source_name, users in users_by_source.items():
        for u in users:
            all_user_ids.add(u['user_id'])

    for uid in all_user_ids:
        # Collect values per source for each field
        field_values = {}
        for source_name, users in users_by_source.items():
            for u in users:
                if u['user_id'] == uid:
                    for field in ['name', 'email', 'created_date', 'status']:
                        val = u.get(field)
                        if val is not None:
                            if field not in field_values:
                                field_values[field] = {}
                            field_values[field][source_name] = val

        # Check each field for conflicts
        for field, src_vals in field_values.items():
            unique_vals = set()
            for v in src_vals.values():
                unique_vals.add(str(v))
            if len(unique_vals) > 1:
                conflict_entry = {
                    'user_id': uid,
                    'field': field,
                    'values': {},
                    'selected': None
                }
                # Add values from each source
                for src in ['source_a', 'source_b', 'source_c']:
                    if src in src_vals:
                        conflict_entry['values'][src] = src_vals[src]

                # Select based on priority
                for src in ['source_a', 'source_b', 'source_c']:
                    if src in src_vals:
                        conflict_entry['selected'] = src_vals[src]
                        break

                conflicts.append(conflict_entry)

    return conflicts


def main():
    # Load all sources
    source_a = load_source_a()
    source_b = load_source_b()
    source_c = load_source_c()

    # Build users_by_source dict for conflict detection
    users_by_source = {
        'source_a': source_a,
        'source_b': source_b,
        'source_c': source_c,
    }

    # Detect conflicts
    conflicts = detect_conflicts(users_by_source)

    # Merge with priority: A > B > C
    merged = {}
    for u in source_a:
        uid = u['user_id']
        merged[uid] = dict(u)
    for u in source_b:
        uid = u['user_id']
        if uid not in merged:
            merged[uid] = dict(u)
        else:
            # Merge fields, keeping A's values
            for k, v in u.items():
                if k not in merged[uid]:
                    merged[uid][k] = v
    for u in source_c:
        uid = u['user_id']
        if uid not in merged:
            merged[uid] = dict(u)
        else:
            for k, v in u.items():
                if k not in merged[uid]:
                    merged[uid][k] = v

    # Build final DataFrame
    rows = []
    for uid, u in merged.items():
        row = {
            'user_id': int(u['user_id']),
            'name': str(u.get('name', '')),
            'email': str(u.get('email', '')),
            'created_date': normalize_date(str(u.get('created_date', ''))),
            'status': str(u.get('status', '')) if u.get('status') is not None else '',
        }
        rows.append(row)

    df = pd.DataFrame(rows)

    # Ensure correct types
    df['user_id'] = df['user_id'].astype(int)
    df['name'] = df['name'].astype(str)
    df['email'] = df['email'].astype(str)
    df['created_date'] = df['created_date'].astype(str)
    df['status'] = df['status'].astype(str)

    # Write output files
    df.to_parquet('/app/merged_users.parquet', index=False)

    # Write conflicts
    with open('/app/conflicts.json', 'w') as f:
        json.dump({
            'total_conflicts': len(conflicts),
            'conflicts': conflicts
        }, f, indent=2)

    print(f"Merged {len(merged)} unique users")
    print(f"Detected {len(conflicts)} conflicts")


if __name__ == '__main__':
    main()
